/*
 * SIMD Vector Addition using Intel AVX Intrinsics
 * 
 * AVX (Advanced Vector Extensions) provides 256-bit registers that can hold
 * 8 x 32-bit floating-point numbers. A single _mm256_add_ps() instruction
 * performs 8 additions simultaneously - true SIMD execution.
 *
 * Compile with: gcc -mavx -o avx_demo avx_demo.c
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define SIZE 10000000 // 10 million elements
#define AVX_FLOAT_COUNT 8 // 256-bit / 32-bit = 8 floats per AVX register

/*
 * Scalar (Non-SIMD) Vector Addition
 * Processes ONE element per iteration
 */
void scalar_add(float* a, float* b, float* result, int n) {
 for (int i = 0; i < n; i++) {
 result[i] = a[i] + b[i];
 }
}

/*
 * SIMD Vector Addition using AVX Intrinsics
 * Processes 8 elements (256 bits) per iteration
 */
void simd_avx_add(float* a, float* b, float* result, int n) {
 int i = 0;

 // Process 8 elements at a time using 256-bit AVX registers
 // _mm256_loadu_ps: loads 8 floats (256 bits) from memory
 // _mm256_add_ps: performs 8 parallel floating-point additions
 // _mm256_storeu_ps: stores 8 results to memory
 for (; i <= n - AVX_FLOAT_COUNT; i += AVX_FLOAT_COUNT) {
 __m256 vec_a = _mm256_loadu_ps(&a[i]); // Load 8 floats into AVX register
 __m256 vec_b = _mm256_loadu_ps(&b[i]); // Load 8 floats into AVX register
 __m256 vec_result = _mm256_add_ps(vec_a, vec_b); // 8 parallel additions!
 _mm256_storeu_ps(&result[i], vec_result); // Store 8 results
 }

 // Handle remaining elements (scalar fallback)
 for (; i < n; i++) {
 result[i] = a[i] + b[i];
 }
}

/*
 * AVX-512 demonstration (for CPUs that support it)
 * 512-bit registers can process 16 floats at once
 */
#ifdef __AVX512F__
void simd_avx512_add(float* a, float* b, float* result, int n) {
 int i = 0;

 for (; i <= n - 16; i += 16) {
 __m512 vec_a = _mm512_loadu_ps(&a[i]);
 __m512 vec_b = _mm512_loadu_ps(&b[i]);
 __m512 vec_result = _mm512_add_ps(vec_a, vec_b);
 _mm512_storeu_ps(&result[i], vec_result);
 }

 // Handle remaining elements
 for (; i < n; i++) {
 result[i] = a[i] + b[i];
 }
}
#endif

void print_sample(float* arr, int n, const char* name) {
 printf("%s (first 8 elements): ", name);
 for (int i = 0; i < 8 && i < n; i++) {
 printf("%.1f ", arr[i]);
 }
 printf("\n");
}

int main() {
 printf("========================================\n");
 printf(" SIMD Vector Addition with AVX\n");
 printf("========================================\n\n");

 // Allocate aligned memory for better AVX performance
 float* a = (float*)aligned_alloc(32, SIZE * sizeof(float));
 float* b = (float*)aligned_alloc(32, SIZE * sizeof(float));
 float* result_scalar = (float*)aligned_alloc(32, SIZE * sizeof(float));
 float* result_simd = (float*)aligned_alloc(32, SIZE * sizeof(float));

 // Initialize with random values
 srand(42);
 for (int i = 0; i < SIZE; i++) {
 a[i] = (float)rand() / RAND_MAX * 100.0f;
 b[i] = (float)rand() / RAND_MAX * 100.0f;
 }

 printf("Array size: %d elements (%.2f MB)\n", SIZE, (SIZE * sizeof(float) * 3) / (1024.0 * 1024.0));
 printf("AVX register width: 256 bits = 8 x 32-bit floats\n");
 printf("Operations per AVX instruction: 8\n\n");

 // Test with small array first
 float test_a[8] = {1, 2, 3, 4, 5, 6, 7, 8};
 float test_b[8] = {10, 20, 30, 40, 50, 60, 70, 80};
 float test_result[8];

 simd_avx_add(test_a, test_b, test_result, 8);
 printf("SIMD Add Example (8 elements):\n");
 print_sample(test_a, 8, "Input A");
 print_sample(test_b, 8, "Input B");
 print_sample(test_result, 8, "Result");
 printf("\nAll 8 additions happen in a SINGLE CPU instruction!\n\n");

 // Benchmark
 clock_t start, end;
 double cpu_time_used;

 // Scalar timing
 start = clock();
 scalar_add(a, b, result_scalar, SIZE);
 end = clock();
 cpu_time_used = ((double)(end - start)) / CLOCKS_PER_SEC;
 printf("Scalar time: %.4f seconds\n", cpu_time_used);

 // SIMD AVX timing
 start = clock();
 simd_avx_add(a, b, result_simd, SIZE);
 end = clock();
 cpu_time_used = ((double)(end - start)) / CLOCKS_PER_SEC;
 printf("SIMD AVX time: %.4f seconds\n", cpu_time_used);

 // Verify correctness
 int errors = 0;
 for (int i = 0; i < SIZE; i++) {
 if (result_scalar[i] != result_simd[i]) {
 errors++;
 if (errors <= 5) {
 printf("Error at index %d: %f vs %f\n", i, result_scalar[i], result_simd[i]);
 }
 }
 }

 if (errors == 0) {
 printf("\n✓ Results verified: SIMD produces identical output!\n");
 }

 // Cleanup
 free(a);
 free(b);
 free(result_scalar);
 free(result_simd);

 return 0;
}
